Add a sticky bulk-action toolbar that appears when selection.count > 0. Two actions for v0.6.2: bulk Close and bulk Add Label. Both iterate the existing `close_github_issue` / `edit_github_issue` Tauri commands via a `Promise.all`-style loop (no new IPC).

### New component: `apps/desktop/src/components/BulkActionToolbar.tsx`

Mounted globally (e.g. in `App.tsx` or `MainContent.tsx`) so it appears regardless of which view (Kanban / Issues / Releases / etc.) is active. Pure floating UI; doesn't interfere with layout.

```tsx
import { useState } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { useSelectionStore, useIssuesStore, useProjectsStore, useToastStore } from '../stores';
import { LabelPickerPopover } from './LabelPickerPopover'; // see below
import './BulkActionToolbar.css';

export function BulkActionToolbar() {
  const projectId = useProjectsStore((s) => s.activeProjectId) ?? 'default';
  const projectPath = useProjectsStore((s) => s.projects.find((p) => p.id === projectId)?.path) ?? null;
  const selected = useSelectionStore((s) => [...(s.selectedByProject[projectId] ?? [])].sort((a, b) => a - b));
  const clear = useSelectionStore((s) => s.clear);
  const triggerIssuesRefetch = useIssuesStore((s) => s.triggerRefetch);
  const addToast = useToastStore((s) => s.addToast);
  const [busy, setBusy] = useState<'close' | 'label' | null>(null);
  const [labelOpen, setLabelOpen] = useState(false);

  if (selected.length === 0) return null;

  const bulkClose = async () => {
    if (busy) return;
    setBusy('close');
    const failures: number[] = [];
    await Promise.all(
      selected.map((n) =>
        invoke('close_github_issue', { number: n, projectPath })
          .catch(() => { failures.push(n); })
      )
    );
    setBusy(null);
    clear();
    triggerIssuesRefetch();
    if (failures.length === 0) {
      addToast({ type: 'success', message: `Closed ${selected.length} issue${selected.length === 1 ? '' : 's'}.` });
    } else {
      addToast({
        type: 'error',
        message: `Closed ${selected.length - failures.length} of ${selected.length}; failed: #${failures.join(', #')}`,
      });
    }
  };

  const bulkAddLabel = async (labelName: string) => {
    if (busy) return;
    setBusy('label');
    setLabelOpen(false);
    const failures: number[] = [];
    await Promise.all(
      selected.map((n) =>
        invoke('edit_github_issue', { number: n, addLabels: [labelName], removeLabels: [], projectPath })
          .catch(() => { failures.push(n); })
      )
    );
    setBusy(null);
    triggerIssuesRefetch();
    if (failures.length === 0) {
      addToast({ type: 'success', message: `Added "${labelName}" to ${selected.length} issue${selected.length === 1 ? '' : 's'}.` });
    } else {
      addToast({ type: 'error', message: `Labeled ${selected.length - failures.length} of ${selected.length}; failed: #${failures.join(', #')}` });
    }
  };

  return (
    <div className="bulk-action-toolbar" role="toolbar" aria-label="Bulk issue actions">
      <span className="bulk-action-count">{selected.length} selected</span>
      <button type="button" disabled={busy !== null} onClick={() => setLabelOpen((v) => !v)}>
        {busy === 'label' ? 'Labeling...' : 'Add label'}
      </button>
      <button type="button" disabled={busy !== null} onClick={bulkClose} className="bulk-action-danger">
        {busy === 'close' ? 'Closing...' : `Close (${selected.length})`}
      </button>
      <button type="button" onClick={clear} disabled={busy !== null}>Clear</button>
      {labelOpen && <LabelPickerPopover onPick={bulkAddLabel} onClose={() => setLabelOpen(false)} />}
    </div>
  );
}
```

### Sub-component: `LabelPickerPopover.tsx`

Fetches available labels via `fetch_github_labels` (existing Tauri command), shows them as a clickable list. Closes on outside click or selection.

```tsx
import { useEffect, useState } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { useProjectsStore } from '../stores';

interface Label { name: string; color: string }

interface LabelPickerPopoverProps {
  onPick: (labelName: string) => void;
  onClose: () => void;
}

export function LabelPickerPopover({ onPick, onClose }: LabelPickerPopoverProps) {
  const projectId = useProjectsStore((s) => s.activeProjectId) ?? 'default';
  const projectPath = useProjectsStore((s) => s.projects.find((p) => p.id === projectId)?.path) ?? null;
  const [labels, setLabels] = useState<Label[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    invoke<Label[]>('fetch_github_labels', { projectPath })
      .then((data) => { setLabels(data); setLoading(false); })
      .catch(() => { setLabels([]); setLoading(false); });
  }, [projectPath]);

  const filtered = labels.filter((l) => l.name.toLowerCase().includes(filter.toLowerCase()));

  return (
    <div className="label-picker-popover" role="dialog" aria-label="Pick a label">
      <input
        type="text"
        autoFocus
        placeholder="Filter labels..."
        value={filter}
        onChange={(e) => setFilter(e.target.value)}
        className="label-picker-filter"
      />
      {loading ? (
        <div className="label-picker-loading">Loading...</div>
      ) : (
        <ul className="label-picker-list">
          {filtered.length === 0 ? (
            <li className="label-picker-empty">No labels match.</li>
          ) : (
            filtered.map((l) => (
              <li key={l.name}>
                <button
                  type="button"
                  className="label-picker-item"
                  onClick={() => onPick(l.name)}
                >
                  <span className="label-picker-color" style={{ background: `#${l.color}` }} />
                  {l.name}
                </button>
              </li>
            ))
          )}
        </ul>
      )}
      <button type="button" className="label-picker-close" onClick={onClose}>Cancel</button>
    </div>
  );
}
```

