### Test file: `apps/desktop/src/stores/__tests__/selectionStore.test.ts`

The selection store reads `useProjectsStore.getState().activeProjectId`. Mock that for the tests.

```ts
import { describe, it, expect, beforeEach, vi } from 'vitest';

// Mock projects store BEFORE importing selectionStore — selectionStore's getProjectId
// is captured at module load.
vi.mock('../projectsStore', () => ({
  useProjectsStore: {
    getState: () => ({ activeProjectId: 'p1' }),
  },
}));

import { useSelectionStore } from '../selectionStore';

function reset() {
  useSelectionStore.setState({ selectedByProject: {} });
}

beforeEach(() => reset());

describe('selectionStore', () => {
  it('toggle adds then removes an issue', () => {
    const s = useSelectionStore.getState();
    s.toggle(42);
    expect(s.isSelected(42)).toBe(true);
    expect(s.count()).toBe(1);
    s.toggle(42);
    expect(s.isSelected(42)).toBe(false);
    expect(s.count()).toBe(0);
  });

  it('selectMany replaces the selection set', () => {
    const s = useSelectionStore.getState();
    s.toggle(1); s.toggle(2);
    s.selectMany([10, 20, 30]);
    expect(s.selected()).toEqual([10, 20, 30]);
    expect(s.isSelected(1)).toBe(false);
  });

  it('addMany unions into the existing selection without removing', () => {
    const s = useSelectionStore.getState();
    s.toggle(1);
    s.addMany([2, 3, 1]); // 1 is duplicate; should not appear twice
    expect(s.selected()).toEqual([1, 2, 3]);
  });

  it('clear empties the selection', () => {
    const s = useSelectionStore.getState();
    s.selectMany([1, 2, 3]);
    s.clear();
    expect(s.count()).toBe(0);
    expect(s.selected()).toEqual([]);
  });
});
```

